import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
} from 'recharts';

function SignalChart({ data, tOn, tOff }) {
  // Compute dynamic Y max
  let yMax = 3.0;
  if (data.length > 0) {
    const maxVal = Math.max(...data.map((d) => d.y));
    yMax = Math.max(maxVal * 1.2, tOn * 1.5, 2.0);
  }

  return (
    <div className="card signal-card">
      <h3>Activation Signal</h3>
      <ResponsiveContainer width="100%" height={180}>
        <LineChart data={data} margin={{ top: 5, right: 10, left: 0, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#222244" />
          <XAxis
            dataKey="x"
            tick={false}
            axisLine={{ stroke: '#333' }}
          />
          <YAxis
            domain={[0, yMax]}
            tick={{ fill: '#555', fontSize: 11 }}
            axisLine={{ stroke: '#333' }}
            width={40}
          />
          <Tooltip
            contentStyle={{
              background: '#1a1a2e',
              border: '1px solid #333',
              borderRadius: 6,
              fontSize: 12,
              fontFamily: 'JetBrains Mono, monospace',
            }}
            labelStyle={{ color: '#888' }}
            formatter={(value) => [value.toFixed(3), 'Activation']}
          />
          <ReferenceLine
            y={tOn}
            stroke="#ff4081"
            strokeDasharray="6 3"
            strokeWidth={1.2}
            label={{ value: `T_ON=${tOn}`, fill: '#ff4081', fontSize: 10, position: 'right' }}
          />
          <ReferenceLine
            y={tOff}
            stroke="#ffd740"
            strokeDasharray="6 3"
            strokeWidth={1}
            label={{ value: `T_OFF=${tOff}`, fill: '#ffd740', fontSize: 10, position: 'right' }}
          />
          <Line
            type="monotone"
            dataKey="y"
            stroke="#00e5ff"
            strokeWidth={1.5}
            dot={false}
            isAnimationActive={false}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

export default SignalChart;
